// Normalize input — accept text or file path
const body = $input.first().json.body || $input.first().json;
const accountId = body.account_id || `acct_${Date.now().toString(36)}`;
const transcript = body.transcript_text || '';

if (!transcript && !body.file_path) {
  throw new Error('Must provide transcript_text or file_path');
}

return [{
  json: {
    account_id: accountId,
    transcript: transcript,
    file_path: body.file_path || null,
    received_at: new Date().toISOString()
  }
}];

// Merge file content or use provided text
const prev = $('Normalize Input').first().json;
const fileContent = $input.first()?.json?.stdout || prev.transcript;

return [{
  json: {
    account_id: prev.account_id,
    transcript: fileContent,
    received_at: prev.received_at
  }
}];

// Rule-based extraction from transcript
// (Ollama version: swap this node's code with Ollama HTTP call)
const transcript = $json.transcript;
const accountId  = $json.account_id;

function extractField(pattern, text, flags='i') {
  const m = text.match(new RegExp(pattern, flags));
  return m ? m[1].trim() : null;
}

function extractPhones(text) {
  return [...text.matchAll(/\b(\d{3}[-.]\d{3}[-.]\d{4})\b/g)].map(m => m[1]);
}

// Company name from transcript header or dialog
const companyFromHeader = extractField('Account:\\s*(.+)', transcript);
const companyFromDialog = extractField("we(?:'re| are)\\s+([A-Z][^,\\.\\n]+(?:LLC|Inc|Services|Solutions|Co\\.|Plumbing|HVAC|Electrical|Refrigeration|Protection)?)", transcript);
const companyName = companyFromHeader || companyFromDialog || accountId;

// Timezone
const tzMap = {'central':'Central Time (CT)','mountain':'Mountain Time (MT)',
               'pacific':'Pacific Time (PT)','eastern':'Eastern Time (ET)'};
let timezone = null;
for (const [k,v] of Object.entries(tzMap)) {
  if (transcript.toLowerCase().includes(k)) { timezone = v; break; }
}

// Business hours
const timeMatches = [...transcript.matchAll(/(\d{1,2}(?::\d{2})?\s*[AP]M)/g)].map(m=>m[1]);
const hasMF = /monday.{1,10}friday/i.test(transcript);

// Address
const addrMatch = transcript.match(/\d{3,5}\s+[A-Z][^,\n]+(?:Road|Street|Ave|Blvd|Way|Drive|Loop|South|East|West|North)[^\n]*/i);

// Phones
const phones = extractPhones(transcript);

// Services (keyword scan)
const svcKeywords = ['hvac','heating','cooling','plumbing','drain','electrical',
  'refrigeration','fire protection','sprinkler','generator','maintenance',
  'installation','repair','water heater','ev charger','indoor air quality','water softener'];
const services = svcKeywords.filter(k => transcript.toLowerCase().includes(k))
                             .map(k => k.replace(/\b\w/g,c=>c.toUpperCase()));

// Emergency triggers (keyword scan)  
const emergencyKws = ['no heat','no ac','burst pipe','flooding','sewage backup',
  'power outage','electrical fire','gas leak','refrigeration down','system down',
  'discharge','sprinkler','temperature','freezer'];
const emergencies = emergencyKws.filter(k => transcript.toLowerCase().includes(k))
                                 .map(k => k.replace(/\b\w/g,c=>c.toUpperCase()));

// Contacts (names near phones)
const contacts = [];
const lines = transcript.split('\n');
for (const line of lines) {
  const phonesInLine = [...line.matchAll(/\d{3}[-.]\d{3}[-.]\d{4}/g)].map(m=>m[0]);
  if (phonesInLine.length) {
    const nameMatch = line.match(/([A-Z][a-z]+\s+[A-Z][a-z]+)/);
    contacts.push({
      name: nameMatch ? nameMatch[1] : `Contact ${contacts.length+1}`,
      phone: phonesInLine[0],
      order: contacts.length + 1
    });
  }
}

// Integration constraints
const tools = ['ServiceTitan','FieldEdge','ServiceTrade','Housecall Pro','Jobber'];
const constraints = tools.filter(t => transcript.toLowerCase().includes(t.toLowerCase()))
                         .map(t => `Do not create jobs/tickets in ${t}`);

const memo = {
  account_id: accountId,
  company_name: companyName,
  version: 'v1',
  created_at: new Date().toISOString(),
  updated_at: new Date().toISOString(),
  source_type: 'demo_call',
  business_hours: {
    days: hasMF ? 'Monday-Friday' : null,
    start: timeMatches[0] || null,
    end:   timeMatches[1] || null,
    timezone: timezone,
    saturday: null,
    sunday: 'Closed'
  },
  office_address: addrMatch ? addrMatch[0].trim() : null,
  services_supported: [...new Set(services)],
  emergency_definition: [...new Set(emergencies)],
  emergency_routing_rules: {
    contacts: contacts.slice(0,3),
    ring_timeout_seconds: 30,
    fallback_action: 'Leave voicemail; inform caller of 30-min callback'
  },
  non_emergency_routing_rules: 'Take name and phone; follow up next business day',
  call_transfer_rules: {
    office_hours_transfer_to: phones[0] || null,
    ring_timeout: '4 rings',
    if_no_answer: 'Take message with name and callback number'
  },
  integration_constraints: constraints,
  after_hours_flow_summary: 'Greet, assess emergency, collect name/phone/address, transfer or message',
  office_hours_flow_summary: 'Greet, collect name, transfer to office line',
  questions_or_unknowns: [],
  notes: 'Extracted via n8n rule-based parser'
};

return [{ json: { account_id: accountId, memo } }];

const { account_id, memo } = $json;
const c = memo.company_name || account_id;
const bh = memo.business_hours || {};
const contacts = memo.emergency_routing_rules?.contacts || [];
const bhDesc = `${bh.days || 'Monday-Friday'} ${bh.start || '8 AM'}–${bh.end || '5 PM'}`;
const tz = bh.timezone || 'local time';
const emergList = (memo.emergency_definition || []).map(e => `- ${e}`).join('\n') || '- Any immediate safety risk';
const svcList = (memo.services_supported || []).map(s => `- ${s}`).join('\n') || '- General services';
const transferSeq = contacts.map(ct => `   Step ${ct.order}: Call ${ct.name} at ${ct.phone}`).join('\n');
const primaryEmerg = contacts[0]?.phone || 'On-call TBD';
const step2 = contacts[1] ? `Call ${contacts[1].name} at ${contacts[1].phone}` : 'Try voicemail on primary';
const constraints = (memo.integration_constraints || []).map(c => `- ${c}`).join('\n') || '- Follow standard protocols';
const officeTransfer = memo.call_transfer_rules?.office_hours_transfer_to || 'Main office line';

const systemPrompt = `You are Clara, a professional virtual receptionist for ${c}.\nNever mention you are AI or automated. Never reference tools or function calls to callers.\n\nBUSINESS HOURS: ${bhDesc} ${tz}\nOFFICE ADDRESS: ${memo.office_address || 'On file'}\n\nSERVICES:\n${svcList}\n\n## BUSINESS HOURS CALL FLOW\n1. GREET: "Thank you for calling ${c}, this is Clara, how can I help you today?"\n2. Listen — do not interrupt.\n3. Collect caller name and callback number.\n4. Transfer to ${officeTransfer}.\n5. TRANSFER FAILS: "Our team is assisting other customers. I have your info and will ensure a prompt callback."\n6. Confirm info. Ask "Anything else?" then close warmly.\n\n## AFTER-HOURS CALL FLOW\n1. GREET: "Thank you for calling ${c}, our office is closed but I'm here to help."\n2. Ask reason for call.\n3. EMERGENCIES:\n${emergList}\n4. IF EMERGENCY: Collect name, phone, address immediately.\n${transferSeq}\n   If all fail: "Urgent message sent. Callback within 30 minutes. Call 911 if life-threatening."\n5. IF NOT EMERGENCY: Collect name + phone. Follow up by 9 AM next business day.\n\n## STRICT RULES\n${constraints}\n- Never quote prices or give estimates.\n- Only collect: name, phone, address (emergencies), brief issue.\n- No more than 3 questions before routing.`;

const agentSpec = {
  agent_name: `${c} - Clara Receptionist`,
  account_id,
  version: 'v1',
  created_at: new Date().toISOString(),
  voice_style: { provider: 'elevenlabs', voice_id: 'Rachel', speed: 1.0 },
  llm_config: { model: 'gpt-4o', temperature: 0.3 },
  system_prompt: systemPrompt,
  key_variables: {
    company_name: c, timezone: tz, business_hours: bhDesc,
    office_address: memo.office_address, emergency_contacts: contacts,
    office_transfer_line: officeTransfer
  },
  call_transfer_protocol: {
    office_hours_primary: officeTransfer,
    ring_timeout: memo.call_transfer_rules?.ring_timeout || '4 rings',
    emergency_sequence: contacts
  },
  fallback_protocol: {
    trigger: 'All transfers exhausted',
    caller_message: `I wasn't able to reach our team directly but an urgent message has been sent. Someone will call you back within 30 minutes.`
  }
};

return [{ json: { account_id, memo, agent_spec: agentSpec } }];

// Create task item in tasks.json
const { account_id, memo } = $json;
const task = {
  task_id: `TASK-N8N-${Date.now().toString(36)}`,
  account_id,
  company_name: memo.company_name || account_id,
  title: `[V1] Review agent config for ${memo.company_name || account_id}`,
  status: 'pending_review',
  created_at: new Date().toISOString(),
  assignee: 'onboarding-team',
  priority: 'high'
};
// In production: POST to Asana API, Linear, etc.
// Here: append to tasks.json (handled by Save Tasks node)
return [{ json: { account_id, company_name: memo.company_name, task } }];
